1	export type Cell = [number, number];
2	
3	const cellKey = (cell: Cell): string => `${cell[0]},${cell[1]}`;
4	
5	const isNeighbor = (cell: Cell, other: Cell): boolean =>
6	  !(other[0] === cell[0] && other[1] === cell[1]) &&
7	  Math.abs(other[0] - cell[0]) <= 1 &&
8	  Math.abs(other[1] - cell[1]) <= 1;
9	
10	const countNeighbors = (cell: Cell, livingCells: Cell[]): number =>
11	  livingCells.filter((other) => isNeighbor(cell, other)).length;
12	
13	const findDeadNeighbors = (livingCells: Cell[]): Cell[] => {
14	  const livingSet = new Set(livingCells.map(cellKey));
15	  const deadNeighbors = new Map<string, Cell>();
16	
17	  for (const cell of livingCells) {
18	    for (let dx = -1; dx <= 1; dx++) {
19	      for (let dy = -1; dy <= 1; dy++) {
20	        if (dx === 0 && dy === 0) continue;
21	        const candidate: Cell = [cell[0] + dx, cell[1] + dy];
22	        const key = cellKey(candidate);
23	        if (!livingSet.has(key)) {
24	          deadNeighbors.set(key, candidate);
25	        }
26	      }
27	    }
28	  }
29	
30	  return [...deadNeighbors.values()];
31	};
32	
33	export function nextGeneration(livingCells: Cell[]): Cell[] {
34	  const survivors = livingCells.filter((cell) => {
35	    const neighbors = countNeighbors(cell, livingCells);
36	    return neighbors === 2 || neighbors === 3;
37	  });
38	
39	  const born = findDeadNeighbors(livingCells).filter(
40	    (cell) => countNeighbors(cell, livingCells) === 3
41	  );
42	
43	  return [...survivors, ...born];
44	}
