1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    const livingCells: Cell[] = [];
7	    const result = nextGeneration(livingCells);
8	    expect(result).toEqual([]);
9	  });
10	  it("should kill a single cell with no neighbors (underpopulation)", () => {
11	    const livingCells: Cell[] = [[0, 0]];
12	    const result = nextGeneration(livingCells);
13	    expect(result).toEqual([]);
14	  });
15	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
16	    const livingCells: Cell[] = [[0, 0], [0, 1]];
17	    const result = nextGeneration(livingCells);
18	    expect(result).toEqual([]);
19	  });
20	  it("should keep a cell alive that has exactly 2 neighbors (survival)", () => {
21	    const livingCells: Cell[] = [[0, 0], [1, 0], [2, 0]];
22	    const result = nextGeneration(livingCells);
23	    expect(result).toContainEqual([1, 0]);
24	  });
25	  it("should keep a cell alive that has exactly 3 neighbors (survival)", () => {
26	    const livingCells: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
27	    const result = nextGeneration(livingCells);
28	    expect(result).toContainEqual([0, 0]);
29	  });
30	  it("should kill a cell that has 4 neighbors (overpopulation)", () => {
31	    const livingCells: Cell[] = [[1, 1], [0, 1], [2, 1], [1, 0], [1, 2]];
32	    const result = nextGeneration(livingCells);
33	    expect(result).not.toContainEqual([1, 1]);
34	  });
35	  it("should bring a dead cell to life when it has exactly 3 neighbors (reproduction)", () => {
36	    const livingCells: Cell[] = [[0, 1], [1, 1], [0, 0]];
37	    const result = nextGeneration(livingCells);
38	    expect(result).toContainEqual([1, 0]);
39	  });
40	  it("should keep a block pattern unchanged (still life)", () => {
41	    const livingCells: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
42	    const result = nextGeneration(livingCells);
43	    const sortCells = (cells: Cell[]) =>
44	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
45	    expect(sortCells(result)).toEqual(sortCells(livingCells));
46	  });
47	  it("should oscillate a blinker pattern (horizontal to vertical)", () => {
48	    const livingCells: Cell[] = [[0, 0], [0, 1], [0, 2]];
49	    const result = nextGeneration(livingCells);
50	    const sortCells = (cells: Cell[]) =>
51	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
52	    const expected: Cell[] = [[-1, 1], [0, 1], [1, 1]];
53	    expect(sortCells(result)).toEqual(sortCells(expected));
54	  });
55	});
